import { axiosInstance, unwrapResponse } from '@/core/api/axiosInstance';

export const emptyToNull = (value) => {
    const next = `${value ?? ''}`.trim();
    return next.length ? next : null;
};

export const toSnakeCase = (value) => {
    const hasValue = value !== null && value !== undefined;

    if (!hasValue) {
        return '';
    }

    return `${value}`.replace(/[A-Z]/g, (match) => `_${match.toLowerCase()}`);
};

/**
 * @template T
 * @param {{ method: string, url: string, data?: unknown, signal?: AbortSignal }} options
 * @returns {Promise<T>}
 */
export async function requestJson({ method, url, data, signal }) {
    const response = await axiosInstance.request({
        method,
        url,
        data,
        signal,
    });

    return unwrapResponse(response);
}
