import { useQuery } from '@tanstack/react-query';
import { useState } from 'react';
import { requestJson } from '@/shared/query/queryHelpers';

const DEFAULT_DETAIL_CACHE_TIME_MS = 5 * 60 * 1000;

export const useListPage = ({
    listQueryKey,
    listUrl,
    detailQueryKey,
    detailUrl,
    initialRequest,
    detailCacheTimeMs = DEFAULT_DETAIL_CACHE_TIME_MS,
}) => {
    const [request, setRequest] = useState(initialRequest);
    const [selectedId, setSelectedId] = useState(null);
    const isDetailOpen = selectedId !== null && selectedId !== undefined;

    const pageQuery = useQuery({
        queryKey: [listQueryKey, request],
        queryFn: ({ signal }) =>
            requestJson({
                method: 'post',
                url: listUrl,
                data: request,
                signal,
            }),
    });

    const detailQuery = useQuery({
        queryKey: [detailQueryKey, selectedId],
        queryFn: ({ signal }) =>
            requestJson({
                method: 'get',
                url: `${detailUrl}/${selectedId}`,
                signal,
            }),
        enabled: isDetailOpen,
        staleTime: detailCacheTimeMs,
        gcTime: detailCacheTimeMs,
    });

    return {
        request,
        setRequest,
        selectedId,
        setSelectedId,
        isDetailOpen,
        pageQuery,
        detailQuery,
    };
};

